import React from 'react';

const Contact = () => {
  return (
    <section id="contact" className="p-8 md:p-20 text-center bg-gray-100">
      <h2 className="text-4xl font-bold mb-6">Contact Me</h2>
      <p className="text-gray-700 mb-6">Feel free to reach out via email or contact form below.</p>
      <form className="max-w-xl mx-auto flex flex-col gap-4">
        <input type="text" placeholder="Name" className="p-3 border rounded"/>
        <input type="email" placeholder="Email" className="p-3 border rounded"/>
        <textarea placeholder="Message" className="p-3 border rounded"></textarea>
        <button type="submit" className="bg-black text-white p-3 rounded hover:bg-red-600 transition">Send</button>
      </form>
    </section>
  );
};

export default Contact;
